5672	\begin{lemma}\leanok
5673	[Sq1 --- composition coherence of \(\mathtt{sheafificationCompPullback}\)]
5674	  \label{lem:sheafificationcomppullback_comp}
5675	  \lean{AlgebraicGeometry.Scheme.Modules.sheafificationCompPullback_comp}
5676	  \uses{lem:sheafification_comp_pullback_eq_leftadjointuniq, lem:sheaf_unit_comp_pushforward_pullbackcomp_inv, lem:sheafificationcomppullback_comp_tail}
5677	  For composable \(h : Z \to Y\), \(f : Y \to X\) and a presheaf \(P\) over \(X\), the
5678	  sheafification--pullback comparison of \(h \circ f\) factors through the comparisons of
5679	  \(f\) and \(h\), conjugated by the sheaf-level pullback pseudofunctor iso
5680	  \(\mathtt{pullbackComp}\,h\,f\) and the sheafified presheaf pullback pseudofunctor iso.
5681	  This is the \(\mathtt{sheafificationCompPullback}\) twin of \cref{lem:pullbackObjUnitToUnit_comp};
5682	  it is the S1-foundational coherence consumed by \cref{lem:pullback_tensor_map_basechange}.
5683	\end{lemma}
5684	\begin{proof}
5685	  \uses{lem:sheafification_comp_pullback_eq_leftadjointuniq, lem:sheaf_unit_comp_pushforward_pullbackcomp_inv, lem:sheafificationcomppullback_comp_tail}
5686	  Proved directly in Lean: both \(\mathtt{sheafificationCompPullback}\) isos are
5687	  \(\mathtt{leftAdjointUniq}\) of composite adjunctions
5688	  (\cref{lem:sheafification_comp_pullback_eq_leftadjointuniq}); transpose the identity under
5689	  the composite adjunction for \(h \circ f\), evaluate the left-hand side by
5690	  \(\mathtt{homEquiv\_leftAdjointUniq\_hom\_app}\), peel the leading
5691	  \(\mathtt{pullbackComp}.\mathrm{inv}\) factor by
5692	  \cref{lem:sheaf_unit_comp_pushforward_pullbackcomp_inv}, and discharge the residual unit
5693	  identity by \cref{lem:sheafificationcomppullback_comp_tail}.
5694	\end{proof}
